import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: {project_basename: {(framework, pkg_id): resolved_version}}
def build_lookup(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                result.setdefault(name, {})[(tfm, pkg['id'])] = pkg['resolvedVersion']
    return result

b = build_lookup(baseline)
a = build_lookup(after)

print('=== CHANGES ===')
changes = False
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for key in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(key)
        av = ap.get(key)
        if bv != av:
            changes = True
            tfm, pkg = key
            print(f'{proj} [{tfm}] | {pkg} | {bv} -> {av}')
if not changes:
    print('No changes')

print()
print('=== UNCHANGED ===')
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for key in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(key)
        av = ap.get(key)
        if bv == av and bv is not None:
            tfm, pkg = key
            print(f'{proj} [{tfm}] | {pkg} | {bv}')
